select count(*) from postgres.comments as c, postgres.posts as p, postgres.postlinks as pl, postgres.posthistory as ph, postgres.votes as v, postgres.users as u where u.id = p.owneruserid and p.id = v.postid and p.id = c.postid and p.id = pl.postid and p.id = ph.postid and p.posttypeid=1 and p.answercount>=0 and p.creationdate>=timestamp '2010-07-21 15:23:53' and p.creationdate<=timestamp '2014-09-11 23:26:14' and pl.creationdate>=timestamp '2010-11-16 01:27:37' and pl.creationdate<=timestamp '2014-08-21 15:25:23' and ph.posthistorytypeid=5 and v.creationdate>=timestamp '2010-07-21 00:00:00' and u.upvotes>=0 and u.creationdate<=timestamp '2014-09-11 20:31:48';
